import re
import pickle
import os
from flask import Flask, request, jsonify
from sklearn.feature_extraction.text import CountVectorizer
from sklearn.linear_model import LogisticRegression
from sklearn.model_selection import train_test_split
import numpy as np
from functools import wraps
import secrets
import hashlib
import time

app = Flask(__name__)

API_KEY = os.environ.get('API_KEY', secrets.token_urlsafe(32))
MAX_EMAIL_LENGTH = 100000
RATE_LIMIT_REQUESTS = 100
RATE_LIMIT_WINDOW = 60

rate_limit_store = {}

def check_api_key(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        api_key = request.headers.get('X-API-Key')
        if not api_key:
            return jsonify({'error': 'API key required'}), 401
        
        expected_hash = hashlib.sha256(API_KEY.encode()).digest()
        provided_hash = hashlib.sha256(api_key.encode()).digest()
        
        if not secrets.compare_digest(expected_hash, provided_hash):
            return jsonify({'error': 'Invalid API key'}), 401
        
        return f(*args, **kwargs)
    return decorated_function

def rate_limit(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        client_ip = request.remote_addr
        current_time = time.time()
        
        if client_ip not in rate_limit_store:
            rate_limit_store[client_ip] = []
        
        rate_limit_store[client_ip] = [
            t for t in rate_limit_store[client_ip] 
            if current_time - t < RATE_LIMIT_WINDOW
        ]
        
        if len(rate_limit_store[client_ip]) >= RATE_LIMIT_REQUESTS:
            return jsonify({'error': 'Rate limit exceeded'}), 429
        
        rate_limit_store[client_ip].append(current_time)
        return f(*args, **kwargs)
    return decorated_function

def sanitize_text(text):
    if not isinstance(text, str):
        raise ValueError("Input must be a string")
    
    if len(text) > MAX_EMAIL_LENGTH:
        raise ValueError(f"Email text exceeds maximum length of {MAX_EMAIL_LENGTH} characters")
    
    text = re.sub(r'[^\w\s@.\-]', ' ', text)
    text = re.sub(r'\s+', ' ', text)
    text = text.strip()
    
    return text

class SpamDetector:
    def __init__(self):
        self.vectorizer = None
        self.model = None
        self.is_trained = False
    
    def train(self, emails, labels):
        if len(emails) != len(labels):
            raise ValueError("Number of emails and labels must match")
        
        if len(emails) == 0:
            raise ValueError("Training data cannot be empty")
        
        sanitized_emails = [sanitize_text(email) for email in emails]
        
        self.vectorizer = CountVectorizer(
            max_features=5000,
            stop_words='english',
            lowercase=True,
            min_df=2,
            max_df=0.95,
            ngram_range=(1, 2)
        )
        
        X = self.vectorizer.fit_transform(sanitized_emails)
        
        self.model = LogisticRegression(
            max_iter=1000,
            random_state=42,
            C=1.0,
            solver='lbfgs'
        )
        
        self.model.fit(X, labels)
        self.is_trained = True
    
    def predict_proba(self, email_text):
        if not self.is_trained:
            raise RuntimeError("Model has not been trained yet")
        
        sanitized_text = sanitize_text(email_text)
        
        X = self.vectorizer.transform([sanitized_text])
        
        proba = self.model.predict_proba(X)[0]
        
        spam_probability = float(proba[1])
        
        return spam_probability
    
    def save_model(self, filepath):
        if not self.is_trained:
            raise RuntimeError("Cannot save untrained model")
        
        model_data = {
            'vectorizer': self.vectorizer,
            'model': self.model
        }
        
        with open(filepath, 'wb') as f:
            pickle.dump(model_data, f)
    
    def load_model(self, filepath):
        if not os.path.exists(filepath):
            raise FileNotFoundError(f"Model file not found: {filepath}")
        
        with open(filepath, 'rb') as f:
            model_data = pickle.load(f)
        
        self.vectorizer = model_data['vectorizer']
        self.model = model_data['model']
        self.is_trained = True

detector = SpamDetector()

